package mhir.gen.verilog

import mhir.gen.{
  DesignCompileFailed,
  SimulationFailed,
  SimulationTimeout,
  TestPassed,
  TestResult,
  TestbenchCompileFailed,
  UnknownFailure
}
import os.{Path, RelPath}

import scala.sys.process._

/** Provides methods for testing a Verilog project generated by
  * [[https://dl.acm.org/doi/10.1145/3385412.3385983 Aetherling]].
  */
object VerilogTestRunner {
  private val VERILOG_DIR = os.pwd / "src" / "test" / "verilog"
  private val RUN_TEST_SH = os.pwd / "src" / "test" / "sh" / "test_verilog.sh"

  /** See [[testExistingProject(dir:Path*]].
    *
    * @param dir
    *   the name of the Verilog project, relative to the `verilog` directory
    *   within this repository.
    * @return
    *   the test result.
    */
  def testExistingProject(dir: String): TestResult = {
    testExistingProject(VERILOG_DIR / RelPath(dir))
  }

  /** Test an existing Verilog project that has both a design and a testbench.
    *
    * @param dir
    *   the path to the Verilog project.
    * @return
    *   the test result.
    */
  def testExistingProject(dir: Path, timeLimit: String = ""): TestResult = {
    val cmd = s"$RUN_TEST_SH $dir"
    val cmdWithTimeout =
      if (timeLimit.isBlank) cmd else s"$cmd --time-limit=$timeLimit"
    cmdWithTimeout.! match {
      case 0 => TestPassed
      case 4 => DesignCompileFailed
      case 5 => TestbenchCompileFailed
      case 6 => SimulationTimeout
      case 7 => SimulationFailed
      case _ => UnknownFailure
    }
  }

  /** Copy the Bash script for running Verilog simulation over to the given
    * directory.
    *
    * @param dir
    *   the Verilog project directory.
    * @return
    *   the path to the Bash script (inside [[dir]]).
    */
  def copyTestBashScript(dir: Path): Path = {
    val shellScriptPath = dir / "test_verilog.sh"
    os.copy.over(from = RUN_TEST_SH, to = shellScriptPath)
    shellScriptPath
  }
}
